#include<bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x=0,f=1;char ch=gc();
		wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
		wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
		return x*f;
	}
	void write(ll x)
	{
		if(x<0)pc('-'),x=-x;
		if(x>9)write(x/10);
		pc(x%10+'0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
CI MAXN=2e5+5,MAXM=3e3+5;
int n,m,dist[MAXN],vis[MAXN],dis[MAXM][MAXM],u[MAXN];
vector<PII> g[MAXN];
queue<int> p;
priority_queue<PII,vector<PII>,greater<> > q;
bool spfa(int s)
{
	FOR(i,0,n)
	{
		dist[i]=1e9;
		vis[i]=0;
	}
	dist[s]=0;
	p.push(s);
	vis[s]=1;
	vector<int> o(n+1,0);
	o[s]=1;
	wh(!p.empty())
	{
		int u=p.front();
		p.pop();
		vis[u]=0;
		FOI(e,g[u])
		{
			int v=e.fst;
			int val=e.snd;
			if(dist[v]>dist[u]+val)
			{
				dist[v]=dist[u]+val;
				if(o[v]>n)return false;
				if(!vis[v])
				{
					++o[v];
					p.push(v);
					vis[v]=1;
				}
			}
		}
	}
	return true;
}
void dijkstra(int s)
{
	wh(!q.empty())q.pop();
	FOR(i,1,n)dis[s][i]=1e9,u[i]=0;
	dis[s][s]=0;
	q.push({0,s});
	wh(!q.empty())
	{
		int d=q.top().fst;
		int k=q.top().snd;
		q.pop();
		if(u[k])continue;
		u[k]=1;
		FOI(e,g[k])
		{
			int v=e.fst;
			int val=e.snd+dist[k]-dist[v];
			if(dis[s][v]>d+val)
			{
				dis[s][v]=d+val;
				q.push({dis[s][v],v});
			}
		}
	}
}
signed main(void)
{
	n=read(),m=read();
	FOR(i,1,m)
	{
		int u=read(),v=read(),w=read();
		g[u].pb({v,w});
	}
	FOR(i,1,n)
    {
        g[0].pb(mk(i,0));
    }
	if(!spfa(0))
	{
		NoAns
		exit(false);
	}
	FOR(i,1,n)
    {
        dijkstra(i);
    }
	FOR(i,1,n)
	{
		int sum=0;
		FOR(j,1,n)
		{
			if(dis[i][j]!=1e9)dis[i][j]+=dist[j]-dist[i];
			sum+=j*dis[i][j];
		}
		writeln(sum);
	}
	return false;
}
